import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  ViewEncapsulation,
} from '@angular/core';

import { cn, type ClassValue } from '{{alias}}/utils';

@Component({
  selector: 'hb-bubble-actions',
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: { '[class]': 'classes()', '[attr.data-slot]': "'bubble-actions'" },
  exportAs: 'hbBubbleActions',
})
export class HbBubbleActionsComponent {
  readonly class = input<ClassValue>('');
  protected readonly classes = computed(() =>
    cn('mt-2 flex flex-wrap items-center gap-1.5', this.class()),
  );
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  ViewEncapsulation,
} from '@angular/core';

import { cn, type ClassValue } from '{{alias}}/utils';
import { type HbBubbleAlign } from './bubble.variants';

@Component({
  selector: 'hb-bubble-group',
  template: `
    @if (hbName() || hbAvatar() || hbTime()) {
      <div class="flex items-center gap-2 px-1 text-xs">
        @if (hbAvatar()) {
          <img [src]="hbAvatar()" alt="" class="size-6 rounded-full object-cover" />
        }
        @if (hbName()) {
          <span class="font-medium">{{ hbName() }}</span>
        }
        @if (hbTime()) {
          <span class="text-muted-foreground">{{ hbTime() }}</span>
        }
      </div>
    }
    <ng-content />
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    '[class]': 'classes()',
    '[attr.data-slot]': "'bubble-group'",
    '[attr.data-align]': 'hbAlign()',
  },
  exportAs: 'hbBubbleGroup',
})
export class HbBubbleGroupComponent {
  readonly hbAlign = input<HbBubbleAlign>('start');
  readonly hbName = input('');
  readonly hbAvatar = input('');
  readonly hbTime = input('');
  readonly class = input<ClassValue>('');

  protected readonly classes = computed(() =>
    cn(
      'flex flex-col gap-1',
      this.hbAlign() === 'end' ? 'items-end' : 'items-start',
      this.class(),
    ),
  );
}

import { ChangeDetectionStrategy, Component, input, ViewEncapsulation } from '@angular/core';
import { NgIcon, provideIcons } from '@ng-icons/core';
import { phosphorDotsThree } from '@ng-icons/phosphor-icons/regular';

import { HbPopoverImports } from '{{alias}}/popover';

@Component({
  selector: 'hb-bubble-menu',
  imports: [NgIcon, HbPopoverImports],
  viewProviders: [provideIcons({ phosphorDotsThree })],
  template: `
    <hb-popover hbTrigger="click" hbSide="top" hbAlign="end">
      <button
        hbPopoverTrigger
        type="button"
        class="inline-flex size-6 items-center justify-center rounded-md text-muted-foreground transition-colors hover:bg-muted hover:text-foreground"
        [attr.aria-label]="hbAriaLabel()"
      >
        <ng-icon name="phosphorDotsThree" />
      </button>
      <div hbPopoverContent class="flex min-w-32 flex-col gap-0.5 p-1">
        <ng-content />
      </div>
    </hb-popover>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: { class: 'inline-flex', '[attr.data-slot]': "'bubble-menu'" },
  exportAs: 'hbBubbleMenu',
})
export class HbBubbleMenuComponent {
  readonly hbAriaLabel = input('More actions');
}

import {
  booleanAttribute,
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  output,
  ViewEncapsulation,
} from '@angular/core';
import { NgIcon, provideIcons } from '@ng-icons/core';
import { phosphorPlus } from '@ng-icons/phosphor-icons/regular';

import { cn, type ClassValue } from '{{alias}}/utils';
import { type HbBubbleReaction } from './bubble.variants';

@Component({
  selector: 'hb-bubble-reactions',
  imports: [NgIcon],
  viewProviders: [provideIcons({ phosphorPlus })],
  template: `
    @for (r of hbReactions(); track r.emoji) {
      <button type="button" [class]="chipClasses(r)" (click)="hbReact.emit(r.emoji)">
        <span>{{ r.emoji }}</span>
        @if (r.count) {
          <span class="tabular-nums">{{ r.count }}</span>
        }
      </button>
    }
    @if (hbAddable()) {
      <button
        type="button"
        class="inline-flex h-6 items-center justify-center rounded-full border border-border px-1.5 text-muted-foreground transition-colors hover:bg-muted hover:text-foreground"
        aria-label="Add reaction"
        (click)="hbAdd.emit()"
      >
        <ng-icon name="phosphorPlus" />
      </button>
    }
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: { '[class]': 'classes()', '[attr.data-slot]': "'bubble-reactions'" },
  exportAs: 'hbBubbleReactions',
})
export class HbBubbleReactionsComponent {
  readonly hbReactions = input<HbBubbleReaction[]>([]);
  readonly hbAddable = input(false, { transform: booleanAttribute });
  readonly class = input<ClassValue>('');

  readonly hbReact = output<string>();
  readonly hbAdd = output<void>();

  protected readonly classes = computed(() =>
    cn('mt-2 flex flex-wrap items-center gap-1', this.class()),
  );
  protected chipClasses(r: HbBubbleReaction): string {
    return cn(
      'inline-flex h-6 items-center gap-1 rounded-full border px-1.5 text-xs transition-colors',
      r.reacted
        ? 'border-primary/40 bg-primary/10 text-foreground'
        : 'border-border bg-background text-muted-foreground hover:bg-muted',
    );
  }
}

import {
  afterRenderEffect,
  booleanAttribute,
  ChangeDetectionStrategy,
  Component,
  computed,
  DestroyRef,
  ElementRef,
  inject,
  input,
  model,
  numberAttribute,
  signal,
  ViewEncapsulation,
  viewChild,
} from '@angular/core';

import { cn, type ClassValue } from '{{alias}}/utils';
import { HbTooltipImports } from '{{alias}}/tooltip';
import { bubbleVariants, type HbBubbleAlign, type HbBubbleVariant } from './bubble.variants';

@Component({
  selector: 'hb-bubble',
  imports: [HbTooltipImports],
  template: `
    <div [class]="bubbleClasses()" [hbTooltip]="hbTooltip()" hbTooltipPosition="top">
      <div #content [style]="clampStyle()">
        <ng-content />
      </div>

      @if (hbCollapsible() && (overflowing() || expanded())) {
        <button
          type="button"
          class="mt-1 text-xs font-medium underline underline-offset-2 opacity-80 hover:opacity-100"
          (click)="expanded.set(!expanded())"
        >
          {{ expanded() ? 'Show less' : 'Show more' }}
        </button>
      }

      <ng-content select="hb-bubble-reactions, hb-bubble-actions, [hbBubbleExtra]" />
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    class: 'flex w-full',
    '[class.justify-end]': "hbAlign() === 'end'",
    '[attr.data-slot]': "'bubble'",
    '[attr.data-align]': 'hbAlign()',
  },
  exportAs: 'hbBubble',
})
export class HbBubbleComponent {
  private readonly destroyRef = inject(DestroyRef);

  readonly hbVariant = input<HbBubbleVariant>('secondary');
  readonly hbAlign = input<HbBubbleAlign>('start');
  readonly hbCollapsible = input(false, { transform: booleanAttribute });
  readonly hbClampLines = input(4, { transform: numberAttribute });
  readonly hbExpanded = model(false);
  readonly hbTooltip = input('');
  readonly class = input<ClassValue>('');

  protected readonly expanded = this.hbExpanded;
  private readonly contentEl = viewChild.required<ElementRef<HTMLElement>>('content');
  protected readonly overflowing = signal(false);
  private readonly resizeTick = signal(0);

  protected readonly clamped = computed(() => this.hbCollapsible() && !this.expanded());
  protected readonly clampStyle = computed<Record<string, string> | null>(() =>
    this.clamped()
      ? {
          display: '-webkit-box',
          '-webkit-line-clamp': String(this.hbClampLines()),
          '-webkit-box-orient': 'vertical',
          overflow: 'hidden',
        }
      : null,
  );
  protected readonly bubbleClasses = computed(() =>
    cn(bubbleVariants({ variant: this.hbVariant(), align: this.hbAlign() }), this.class()),
  );

  constructor() {
    afterRenderEffect(() => {
      this.hbCollapsible();
      this.hbClampLines();
      this.expanded();
      this.resizeTick();
      const el = this.contentEl().nativeElement;
      this.overflowing.set(el.scrollHeight - el.clientHeight > 1);
    });

    const RO = (globalThis as { ResizeObserver?: typeof ResizeObserver }).ResizeObserver;
    const ro = RO ? new RO(() => this.resizeTick.update((v) => v + 1)) : null;
    afterRenderEffect(() => ro?.observe(this.contentEl().nativeElement));
    this.destroyRef.onDestroy(() => ro?.disconnect());
  }
}

import { HbBubbleActionsComponent } from './bubble-actions.component';
import { HbBubbleComponent } from './bubble.component';
import { HbBubbleGroupComponent } from './bubble-group.component';
import { HbBubbleMenuComponent } from './bubble-menu.component';
import { HbBubbleReactionsComponent } from './bubble-reactions.component';

export const HbBubbleImports = [
  HbBubbleComponent,
  HbBubbleGroupComponent,
  HbBubbleActionsComponent,
  HbBubbleReactionsComponent,
  HbBubbleMenuComponent,
] as const;

import { cva, type VariantProps } from 'class-variance-authority';

export const bubbleVariants = cva(
  'relative w-fit max-w-[min(32rem,85%)] rounded-xl px-3.5 py-2 text-sm leading-relaxed break-words',
  {
    variants: {
      variant: {
        default: 'bg-primary text-primary-foreground',
        secondary: 'bg-secondary text-secondary-foreground',
        muted: 'bg-muted/60 text-muted-foreground',
        tinted: 'bg-primary/10 text-foreground',
        outline: 'border border-border bg-background text-foreground',
        ghost: 'bg-transparent px-0 py-0 text-foreground',
        destructive: 'border border-destructive/30 bg-destructive/10 text-destructive',
      },
      align: {
        start: 'rounded-bl-sm',
        end: 'rounded-br-sm',
      },
    },
    compoundVariants: [
      { variant: 'ghost', align: 'start', class: 'rounded-none' },
      { variant: 'ghost', align: 'end', class: 'rounded-none' },
    ],
    defaultVariants: { variant: 'secondary', align: 'start' },
  },
);

export type HbBubbleVariant = NonNullable<VariantProps<typeof bubbleVariants>['variant']>;
export type HbBubbleAlign = NonNullable<VariantProps<typeof bubbleVariants>['align']>;

export interface HbBubbleReaction {
  emoji: string;
  count?: number;
  reacted?: boolean;
}

export * from './bubble.component';
export * from './bubble-group.component';
export * from './bubble-actions.component';
export * from './bubble-reactions.component';
export * from './bubble-menu.component';
export * from './bubble.variants';
export * from './bubble.imports';

